Steps:
[AUTH role=ORG_USER]
[GQL-OP orders_list]
  query {
    orders(first: 10, sort: "createdDate:desc") {
      totalCount
      items {
        id number status createdDate
        total { amount currency { code } }
      }
    }
  }
[GQL-EXEC orders_list]

[AUTH role=ORG_USER]
[GQL-OP list_first]
  query {
    orders(first: 1, sort: "createdDate:desc") {
      items { number }
    }
  }
[GQL-EXEC list_first]
[GQL-CAPTURE list_first.data.orders.items.0.number → ORDER_NUMBER]
[GQL-OP order_detail]
  query {
    order(number: "{{ORDER_NUMBER}}") {
      id number status createdDate
      customerId customerName storeId storeName
      total { amount currency { code } }
      subTotal { amount }
      shippingTotal { amount }
      taxTotal { amount }
      discountTotal { amount }
      items { id productId sku name quantity price { amount } }
      addresses { id city countryCode firstName lastName line1 }
      inPayments { id gatewayCode paymentMethod { code paymentMethodType } sum { amount } }
      shipments { id shipmentMethodCode deliveryAddress { city countryCode line1 } price { amount } }
    }
  }
[GQL-EXEC order_detail]

[AUTH role=ORG_USER]
[GQL-OP list_first]
  query {
    orders(first: 1, sort: "createdDate:desc") {
      items { number }
    }
  }
[GQL-EXEC list_first]
[GQL-CAPTURE list_first.data.orders.items.0.number → ORDER_NUMBER]
[GQL-OP order_full]
  query {
    order(number: "{{ORDER_NUMBER}}") {
      id operationType parentOperationId number isApproved status statusDisplayValue
      comment outerId isCancelled cancelledDate cancelReason objectType
      customerId customerName channelId storeId storeName
      organizationId organizationName employeeId employeeName
      shoppingCartId isPrototype subscriptionNumber subscriptionId purchaseOrderNumber
      taxType taxPercentRate languageCode
      createdDate createdBy modifiedDate modifiedBy
      currency { code name symbol exchangeRate }
      total { amount formattedAmount currency { code } }
      taxTotal { amount }
      discountAmount { amount }
      subTotal { amount } subTotalWithTax { amount }
      subTotalDiscount { amount } subTotalDiscountWithTax { amount }
      subTotalTaxTotal { amount }
      shippingTotal { amount } shippingTotalWithTax { amount }
      shippingSubTotal { amount } shippingSubTotalWithTax { amount }
      shippingDiscountTotal { amount } shippingDiscountTotalWithTax { amount }
      shippingTaxTotal { amount }
      paymentTotal { amount } paymentTotalWithTax { amount }
      paymentSubTotal { amount } paymentSubTotalWithTax { amount }
      paymentDiscountTotal { amount } paymentDiscountTotalWithTax { amount }
      paymentTaxTotal { amount }
      discountTotal { amount } discountTotalWithTax { amount }
      fee { amount } feeWithTax { amount }
      feeTotal { amount } feeTotalWithTax { amount }
      addresses {
        id city countryCode countryName firstName lastName
        line1 line2 postalCode regionId regionName phone email addressType
      }
      items {
        id productId sku name quantity
        price { amount } extendedPrice { amount } discountAmount { amount }
        taxTotal { amount } taxPercentRate placedPrice { amount }
      }
      inPayments {
        id number status gatewayCode
        paymentMethod { code typeName paymentMethodType paymentMethodGroupType }
        sum { amount } tax { amount }
        billingAddress { city line1 countryCode postalCode }
      }
      shipments {
        id number status shipmentMethodCode shipmentMethodOption
        deliveryAddress { city line1 countryCode postalCode }
        price { amount } taxTotal { amount }
        items { lineItemId quantity }
      }
      taxDetails { name rate { amount } amount { amount } }
      dynamicProperties { name value valueType }
      coupons
      discounts { promotionId description amount { amount } coupon }
      availablePaymentMethods { code paymentMethodType paymentMethodGroupType }
    }
  }
[GQL-EXEC order_full]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cultureName: "{{culture}}" currencyCode: "{{currency}}" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP discover_product]
  query {
    products(
      storeId: "{{STORE_ID}}"
      cultureName: "{{culture}}"
      currencyCode: "{{currency}}"
      filter: "category.subtree:{{product_id}}"
      first: 1
    ) { items { id slug } }
  }
[GQL-EXEC discover_product]
[GQL-CAPTURE discover_product.data.products.items.0.id → PROD_ID]
[GQL-OP add_item]
  mutation {
    addItem(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      cultureName: "{{culture}}" currencyCode: "{{currency}}"
      productId: "{{PROD_ID}}" quantity: 1
    }) { id }
  }
[GQL-EXEC add_item]
[GQL-OP add_payment]
  mutation {
    addOrUpdateCartPayment(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      cultureName: "{{culture}}" currencyCode: "{{currency}}"
      payment: { paymentGatewayCode: "{{gateway}}" }
    }) {
      id
      payments { id paymentGatewayCode }
    }
  }
[GQL-EXEC add_payment]
[GQL-CAPTURE add_payment.data.addOrUpdateCartPayment.id → CART_ID]
[GQL-CAPTURE add_payment.data.addOrUpdateCartPayment.payments.0.id → PAYMENT_ID]
[GQL-OP init_cart_payment]
  mutation {
    initializeCartPayment(command: {
      cartId: "{{CART_ID}}"
      paymentId: "{{PAYMENT_ID}}"
    }) {
      isSuccess
      errorMessage
      publicParameters { key value }
    }
  }
[GQL-EXEC init_cart_payment]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cultureName: "{{culture}}" currencyCode: "{{currency}}" }) { id } }
[GQL-EXEC cleanup_post]

[AUTH role=ORG_USER]
[GQL-OP init_bad]
  mutation {
    initializeCartPayment(command: {
      cartId: "{{bad_cart_id}}"
      paymentId: "{{bad_payment_id}}"
    }) {
      isSuccess
      errorMessage
      publicParameters { key value }
    }
  }
[GQL-EXEC init_bad]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cultureName: "{{culture}}" currencyCode: "{{currency}}" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP discover_product]
  query {
    products(storeId: "{{STORE_ID}}" cultureName: "{{culture}}" currencyCode: "{{currency}}" filter: "category.subtree:{{product_id}}" first: 1)
    { items { id slug } }
  }
[GQL-EXEC discover_product]
[GQL-CAPTURE discover_product.data.products.items.0.id → PROD_ID]
[GQL-OP add_item]
  mutation {
    addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cultureName: "{{culture}}" currencyCode: "{{currency}}" productId: "{{PROD_ID}}" quantity: 1 })
    { id }
  }
[GQL-EXEC add_item]
[GQL-OP read_cart]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cultureName: "{{culture}}" currencyCode: "{{currency}}") {
      availablePaymentMethods {
        code
        name
        allowCartPayment
      }
    }
  }
[GQL-EXEC read_cart]
[GQL-CAPTURE read_cart.data.cart.availablePaymentMethods[?code=SkyflowPaymentMethod].allowCartPayment → SKY_ALLOW_CART]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cultureName: "{{culture}}" currencyCode: "{{currency}}" }) { id } }
[GQL-EXEC cleanup_post]
